// // This module implements a 16-bit down counter that decrements its value on every positive edge of a clock signal. It has an asynchronous reset input that sets the counter value to zero when activated. Additionally, provide an enable signal that allows the counter to decrement only when it is low.
module counter_16bit (
    input clk,
    input reset,
    input enable,
    output reg [15:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 16'b0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
